 1→#!/usr/bin/env node
 2→
 3→/**
 4→ * Shatter TypeScript frontend entry point.
 5→ *
 6→ * Reads newline-delimited JSON protocol messages from stdin and writes
 7→ * responses to stdout. Debug output goes to stderr.
 8→ */
 9→
10→import * as readline from "node:readline";
11→import { handleRequest, parseRequest } from "./handlers.js";
12→import logger from "./logger.js";
13→import { PROTOCOL_VERSION, type Response } from "./protocol.js";
14→
15→function sendResponse(response: Response): void {
16→  const json = JSON.stringify(response);
17→  process.stdout.write(json + "\n");
18→  logger.trace({ raw: json }, "Sent");
19→}
20→
21→function main(): void {
22→  logger.debug("Starting TypeScript frontend (protocol 0.1.0)");
23→
24→  const rl = readline.createInterface({
25→    input: process.stdin,
26→    terminal: false,
27→  });
28→
29→  rl.on("line", (line: string) => {
30→    const trimmed = line.trim();
31→    if (trimmed === "") return;
32→
33→    logger.trace({ raw: trimmed }, "Received");
34→
35→    const result = parseRequest(trimmed);
36→
37→    if ("error" in result) {
38→      sendResponse(result.error);
39→      return;
40→    }
41→
42→    const requestId = result.request.id;
43→    void handleRequest(result.request).then(({ response, shutdown }) => {
44→      sendResponse(response);
45→
46→      if (shutdown) {
47→        logger.debug("Shutting down");
48→        rl.close();
49→      }
50→    }).catch((err: unknown) => {
51→      const msg = err instanceof Error ? err.message : String(err);
52→      logger.error("Unhandled error processing request %s: %s", requestId, msg);
53→      sendResponse({
54→        protocol_version: PROTOCOL_VERSION,
55→        id: requestId,
56→        status: "error",
57→        code: "internal_error",
58→        message: `Unhandled error: ${msg}`,
59→      } as Response);
60→    });
61→  });
62→
63→  rl.on("close", () => {
64→    logger.debug("Stdin closed, exiting");
65→    process.exit(0);
66→  });
67→}
68→
69→main();
70→

  1→/**
  2→ * Command handlers for the Shatter protocol.
  3→ *
  4→ * Each handler receives a typed request and returns a typed response.
  5→ * The instrument handler stores instrumented source in memory so the
  6→ * execute handler can use it for branch-recording execution.
  7→ */
  8→
  9→import * as fs from "node:fs";
 10→import * as path from "node:path";
 11→import {
 12→  PROTOCOL_VERSION,
 13→  FRONTEND_LANGUAGE,
 14→  type Request,
 15→  type Response,
 16→  type ErrorResponse,
 17→  type SetupLevel,
 18→} from "./protocol.js";
 19→import { analyzeFile } from "./analyzer.js";
 20→import { instrumentFunction } from "./instrumentor.js";
 21→import {
 22→  executeFunction,
 23→  executeInstrumented,
 24→  buildExecuteResponse,
 25→  setProjectRoot,
 26→  clearModuleCache,
 27→} from "./executor.js";
 28→import {
 29→  loadSetupModule,
 30→  runSetup,
 31→  runTeardown,
 32→  loadGeneratorModule,
 33→  runGenerator,
 34→  type SetupModule,
 35→} from "./setup-loader.js";
 36→import {
 37→  loadWasmPlugin,
 38→  runWasmGenerator,
 39→  clearWasmCache,
 40→} from "./wasm-generator.js";
 41→
 42→/** Supported capabilities for this frontend. */
 43→const SUPPORTED_CAPABILITIES = [
 44→  "analyze", "execute", "instrument", "setup", "generate",
 45→  "complex_type:date", "complex_type:date_time", "complex_type:duration",
 46→  "complex_type:reg_exp", "complex_type:url", "complex_type:big_int",
 47→  "complex_type:buffer", "complex_type:error", "complex_type:symbol",
 48→];
 49→
 50→/** Track the last analyzed file so execute can resolve function references. */
 51→let lastAnalyzedFile: string | null = null;
 52→
 53→/**
 54→ * Stored instrumented sources, keyed by "file:function".
 55→ * Set by the instrument handler, consumed by the execute handler.
 56→ */
 57→const instrumentedSources = new Map<string, string>();
 58→
 59→/**
 60→ * Loaded setup modules, keyed by file path.
 61→ * Cached so teardown can use the same module instance as setup.
 62→ */
 63→const loadedSetupModules = new Map<string, SetupModule>();
 64→
 65→/**
 66→ * Setup contexts keyed by "level:scope" (e.g. "function:myFunc", "session:main").
 67→ * Separate keys per level ensure that session-, file-, function-, and
 68→ * execution-level contexts coexist without collision.
 69→ */
 70→const setupContexts = new Map<string, { module: SetupModule; context: unknown }>();
 71→
 72→/** Build a composite cache key for the setup context map. */
 73→function setupContextKey(level: SetupLevel, scope: string): string {
 74→  return `${level}:${scope}`;
 75→}
 76→
 77→/**
 78→ * Dispatch a parsed request to the appropriate handler.
 79→ *
 80→ * Returns a Response and a shutdown flag. The handler is async because
 81→ * WASM generator loading requires awaiting plugin creation.
 82→ */
 83→export async function handleRequest(request: Request): Promise<{ response: Response; shutdown: boolean }> {
 84→  if (!isVersionCompatible(request.protocol_version)) {
 85→    return {
 86→      response: errorResponse(request.id, "version_mismatch",
 87→        `Unsupported protocol version: ${request.protocol_version} (expected ${PROTOCOL_VERSION})`),
 88→      shutdown: false,
 89→    };
 90→  }
 91→
 92→  switch (request.command) {
 93→    case "handshake":
 94→      return {
 95→        response: {
 96→          protocol_version: PROTOCOL_VERSION,
 97→          id: request.id,
 98→          status: "handshake",
 99→          frontend_version: PROTOCOL_VERSION,
100→          language: FRONTEND_LANGUAGE,
101→          capabilities: SUPPORTED_CAPABILITIES,
102→        },
103→        shutdown: false,
104→      };
105→
106→    case "analyze": {
107→      if (!fs.existsSync(request.file)) {
108→        return {
109→          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
110→          shutdown: false,
111→        };
112→      }
113→
114→      lastAnalyzedFile = path.resolve(request.file);
115→      setProjectRoot(request.project_root);
116→      const functions = analyzeFile(request.file, request.function, request.project_root);
117→
118→      if (request.function != null && functions.length === 0) {
119→        return {
120→          response: errorResponse(
121→            request.id,
122→            "function_not_found",
123→            `Function not found: ${request.function} in ${request.file}`,
124→          ),
125→          shutdown: false,
126→        };
127→      }
128→
129→      return {
130→        response: {
131→          protocol_version: PROTOCOL_VERSION,
132→          id: request.id,
133→          status: "analyze",
134→          functions,
135→        },
136→        shutdown: false,
137→      };
138→    }
139→
140→    case "instrument": {
141→      if (!fs.existsSync(request.file)) {
142→        return {
143→          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
144→          shutdown: false,
145→        };
146→      }
147→
148→      const source = fs.readFileSync(request.file, "utf-8");
149→      const result = instrumentFunction(source, request.function, request.file, request.mocks ?? []);
150→
151→      if ("error" in result) {
152→        return {
153→          response: errorResponse(request.id, "instrumentation_failed", result.error),
154→          shutdown: false,
155→        };
156→      }
157→
158→      // Store the instrumented source for use by the execute handler.
159→      // Use resolved path so keys match execute's resolved fileForExec.
160→      const key = `${path.resolve(request.file)}:${request.function}`;
161→      instrumentedSources.set(key, result.instrumentedSource);
162→      lastAnalyzedFile = path.resolve(request.file);
163→
164→      return {
165→        response: {
166→          protocol_version: PROTOCOL_VERSION,
167→          id: request.id,
168→          status: "instrument",
169→          instrumented: true,
170→          output_file: null,
171→          instrumentable_line_count: result.instrumentableLineCount,
172→        },
173→        shutdown: false,
174→      };
175→    }
176→
177→    case "execute": {
178→      const funcRef = request.function;
179→      const fileForExec = resolveFileForExecute(funcRef);
180→
181→      if (!fileForExec) {
182→        return {
183→          response: errorResponse(
184→            request.id,
185→            "function_not_found",
186→            `Cannot resolve file for function: ${funcRef}. Use file:function format.`,
187→          ),
188→          shutdown: false,
189→        };
190→      }
191→
192→      try {
193→        // Check if we have instrumented source for this function
194→        const funcName = funcRef.includes(":") ? funcRef.split(":").pop()! : funcRef;
195→        const instrumentKey = `${fileForExec}:${funcName}`;
196→        const instrumentedSource = instrumentedSources.get(instrumentKey);
197→
198→        let rawResult;
199→        if (instrumentedSource) {
200→          rawResult = await executeInstrumented(instrumentedSource, funcName, request.inputs, request.mocks ?? [], fileForExec);
201→        } else {
202→          rawResult = await executeFunction(fileForExec, funcRef, request.inputs);
203→        }
204→
205→        return {
206→          response: buildExecuteResponse(request.id, PROTOCOL_VERSION, rawResult),
207→          shutdown: false,
208→        };
209→      } catch (e: unknown) {
210→        const msg = e instanceof Error ? e.message : String(e);
211→        return {
212→          response: errorResponse(request.id, "internal_error", `Execute failed: ${msg}`),
213→          shutdown: false,
214→        };
215→      }
216→    }
217→
218→    case "setup": {
219→      if (!fs.existsSync(request.file)) {
220→        return {
221→          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
222→          shutdown: false,
223→        };
224→      }
225→
226→      try {
227→        let setupModule = loadedSetupModules.get(request.file);
228→        if (!setupModule) {
229→          setupModule = loadSetupModule(request.file);
230→          loadedSetupModules.set(request.file, setupModule);
231→        }
232→
233→        const setupContext = await runSetup(
234→          setupModule, request.scope, request.level, request.parent_context,
235→        );
236→        const ctxKey = setupContextKey(request.level, request.scope);
237→        setupContexts.set(ctxKey, { module: setupModule, context: setupContext });
238→
239→        return {
240→          response: {
241→            protocol_version: PROTOCOL_VERSION,
242→            id: request.id,
243→            status: "setup",
244→            setup_context: setupContext,
245→          },
246→          shutdown: false,
247→        };
248→      } catch (e: unknown) {
249→        const msg = e instanceof Error ? e.message : String(e);
250→        return {
251→          response: errorResponse(request.id, "internal_error", `Setup failed: ${msg}`),
252→          shutdown: false,
253→        };
254→      }
255→    }
256→
257→    case "teardown": {
258→      try {
259→        const ctxKey = setupContextKey(request.level, request.scope);
260→        const stored = setupContexts.get(ctxKey);
261→        if (!stored) {
262→          return {
263→            response: errorResponse(
264→              request.id,
265→              "internal_error",
266→              `No setup context found for ${request.level}:${request.scope}. Call setup first.`,
267→            ),
268→            shutdown: false,
269→          };
270→        }
271→
272→        await runTeardown(stored.module, request.scope, stored.context);
273→        setupContexts.delete(ctxKey);
274→        instrumentedSources.clear();
275→        clearModuleCache();
276→
277→        return {
278→          response: {
279→            protocol_version: PROTOCOL_VERSION,
280→            id: request.id,
281→            status: "teardown_ack",
282→          },
283→          shutdown: false,
284→        };
285→      } catch (e: unknown) {
286→        const msg = e instanceof Error ? e.message : String(e);
287→        return {
288→          response: errorResponse(request.id, "internal_error", `Teardown failed: ${msg}`),
289→          shutdown: false,
290→        };
291→      }
292→    }
293→
294→    case "generate": {
295→      if (!fs.existsSync(request.file)) {
296→        return {
297→          response: errorResponse(request.id, "file_not_found", `File not found: ${request.file}`),
298→          shutdown: false,
299→        };
300→      }
301→
302→      try {
303→        if (request.file.endsWith(".wasm")) {
304→          const plugin = await loadWasmPlugin(request.file);
305→          const result = await runWasmGenerator(plugin, request.name, request.recipe);
306→
307→          return {
308→            response: {
309→              protocol_version: PROTOCOL_VERSION,
310→              id: request.id,
311→              status: "generate",
312→              value: result.value,
313→              generator_id: result.id,
314→              ...(result.recipe !== undefined ? { recipe: result.recipe } : {}),
315→            },
316→            shutdown: false,
317→          };
318→        }
319→
320→        const generatorModule = loadGeneratorModule(request.file);
321→        const value = runGenerator(generatorModule, request.name, request.kind);
322→
323→        return {
324→          response: {
325→            protocol_version: PROTOCOL_VERSION,
326→            id: request.id,
327→            status: "generate",
328→            value,
329→            generator_id: "generated",
330→          },
331→          shutdown: false,
332→        };
333→      } catch (e: unknown) {
334→        const msg = e instanceof Error ? e.message : String(e);
335→        return {
336→          response: errorResponse(request.id, "internal_error", `Generate failed: ${msg}`),
337→          shutdown: false,
338→        };
339→      }
340→    }
341→
342→    case "shutdown":
343→      await clearWasmCache();
344→      instrumentedSources.clear();
345→      clearModuleCache();
346→      return {
347→        response: {
348→          protocol_version: PROTOCOL_VERSION,
349→          id: request.id,
350→          status: "shutdown_ack",
351→        },
352→        shutdown: true,
353→      };
354→  }
355→}
356→
357→/**
358→ * Resolve the file path for an execute request.
359→ *
360→ * The function reference can be in "file:function" format or just a function name.
361→ * If just a name, falls back to the last analyzed file.
362→ */
363→function resolveFileForExecute(funcRef: string): string | null {
364→  if (funcRef.includes(":")) {
365→    // file:function format — extract the file part
366→    const lastColon = funcRef.lastIndexOf(":");
367→    const file = funcRef.substring(0, lastColon);
368→    if (fs.existsSync(file)) {
369→      return path.resolve(file);
370→    }
371→  }
372→
373→  // Fall back to last analyzed file (already resolved on store)
374→  return lastAnalyzedFile;
375→}
376→
377→function isVersionCompatible(version: string): boolean {
378→  // For now, require exact match on major.minor
379→  const [reqMajor, reqMinor] = version.split(".").map(Number);
380→  const [ourMajor, ourMinor] = PROTOCOL_VERSION.split(".").map(Number);
381→  return reqMajor === ourMajor && reqMinor === ourMinor;
382→}
383→
384→function errorResponse(id: number, code: ErrorResponse["code"], message: string): ErrorResponse {
385→  return {
386→    protocol_version: PROTOCOL_VERSION,
387→    id,
388→    status: "error",
389→    code,
390→    message,
391→  };
392→}
393→
394→/**
395→ * Parse a JSON string into a Request, returning an error response if invalid.
396→ */
397→export function parseRequest(line: string): { request: Request } | { error: ErrorResponse } {
398→  let parsed: unknown;
399→  try {
400→    parsed = JSON.parse(line);
401→  } catch {
402→    return {
403→      error: errorResponse(0, "invalid_request", `Invalid JSON: ${line.slice(0, 100)}`),
404→    };
405→  }
406→
407→  if (typeof parsed !== "object" || parsed === null) {
408→    return {
409→      error: errorResponse(0, "invalid_request", "Request must be a JSON object"),
410→    };
411→  }
412→
413→  const obj = parsed as Record<string, unknown>;
414→
415→  if (typeof obj["id"] !== "number") {
416→    return {
417→      error: errorResponse(0, "invalid_request", "Request must have a numeric 'id' field"),
418→    };
419→  }
420→
421→  const id = obj["id"] as number;
422→
423→  if (typeof obj["protocol_version"] !== "string") {
424→    return {
425→      error: errorResponse(id, "invalid_request", "Request must have a 'protocol_version' string field"),
426→    };
427→  }
428→
429→  if (typeof obj["command"] !== "string") {
430→    return {
431→      error: errorResponse(id, "invalid_request", "Request must have a 'command' string field"),
432→    };
433→  }
434→
435→  const validCommands = ["handshake", "analyze", "instrument", "execute", "setup", "teardown", "generate", "shutdown"];
436→  if (!validCommands.includes(obj["command"] as string)) {
437→    return {
438→      error: errorResponse(id, "invalid_request", `Unknown command: ${String(obj["command"])}`),
439→    };
440→  }
441→
442→  return { request: parsed as Request };
443→}
444→
445→/**
446→ * Clear stored instrumented sources and setup state. Useful for testing.
447→ */
448→export function clearInstrumentedSources(): void {
449→  instrumentedSources.clear();
450→  loadedSetupModules.clear();
451→  setupContexts.clear();
452→}
453→
454→/** Number of cached instrumented sources. Exposed for testing. */
455→export function instrumentedSourcesSize(): number {
456→  return instrumentedSources.size;
457→}
458→
459→/** Number of cached setup contexts. Exposed for testing. */
460→export function setupContextsSize(): number {
461→  return setupContexts.size;
462→}
463→

  1→/**
  2→ * Setup and generator module loader for the Shatter TypeScript frontend.
  3→ *
  4→ * Loads user-provided setup/teardown and generator files using the same
  5→ * vm.createContext + TypeScript transpile pattern as executor.ts.
  6→ */
  7→
  8→import * as ts from "typescript";
  9→import * as fs from "node:fs";
 10→import * as vm from "node:vm";
 11→import * as path from "node:path";
 12→import { createRequire } from "node:module";
 13→import type { SetupLevel, SetupContextStack, GeneratorKind } from "./protocol.js";
 14→
 15→/** Default setup timeout in milliseconds (30 seconds). */
 16→const DEFAULT_SETUP_TIMEOUT_MS = 30_000;
 17→
 18→/**
 19→ * Read SHATTER_SETUP_TIMEOUT env var (seconds) and return milliseconds.
 20→ * Default: 30s. Ignores non-positive or non-numeric values.
 21→ */
 22→export function getSetupTimeoutMs(): number {
 23→  const raw = process.env["SHATTER_SETUP_TIMEOUT"];
 24→  if (raw !== undefined) {
 25→    const secs = parseFloat(raw);
 26→    if (Number.isFinite(secs) && secs > 0) {
 27→      return secs * 1000;
 28→    }
 29→  }
 30→  return DEFAULT_SETUP_TIMEOUT_MS;
 31→}
 32→
 33→/** A loaded setup module with its exports available for calling. */
 34→export interface SetupModule {
 35→  exports: Record<string, unknown>;
 36→  filePath: string;
 37→}
 38→
 39→/** A loaded generator module with its exports available for calling. */
 40→export interface GeneratorModule {
 41→  exports: Record<string, unknown>;
 42→  filePath: string;
 43→}
 44→
 45→/**
 46→ * Transpile and load a TypeScript/JavaScript file, returning its exports.
 47→ */
 48→function loadAndTranspile(filePath: string): Record<string, unknown> {
 49→  const absolutePath = path.resolve(filePath);
 50→  const source = fs.readFileSync(absolutePath, "utf-8");
 51→  const result = ts.transpileModule(source, {
 52→    compilerOptions: {
 53→      target: ts.ScriptTarget.ES2022,
 54→      module: ts.ModuleKind.CommonJS,
 55→      esModuleInterop: true,
 56→      strict: true,
 57→      jsx: ts.JsxEmit.ReactJSX,
 58→    },
 59→    fileName: absolutePath,
 60→  });
 61→
 62→  const targetRequire = createRequire(absolutePath);
 63→  const moduleExports: Record<string, unknown> = {};
 64→  const moduleObj = { exports: moduleExports };
 65→
 66→  const sandbox = vm.createContext({
 67→    module: moduleObj,
 68→    exports: moduleExports,
 69→    require: targetRequire,
 70→    console,
 71→    process,
 72→    Buffer,
 73→    setTimeout,
 74→    clearTimeout,
 75→    setInterval,
 76→    clearInterval,
 77→    __filename: absolutePath,
 78→    __dirname: path.dirname(absolutePath),
 79→  });
 80→
 81→  vm.runInContext(result.outputText, sandbox, { filename: absolutePath });
 82→
 83→  const finalExports = (sandbox as Record<string, unknown>)["module"] as {
 84→    exports: Record<string, unknown>;
 85→  };
 86→  return finalExports.exports;
 87→}
 88→
 89→/**
 90→ * Load a setup module file. The file should export a `setup()` function
 91→ * and optionally a `teardown()` function.
 92→ */
 93→export function loadSetupModule(file: string): SetupModule {
 94→  const exports = loadAndTranspile(file);
 95→  return { exports, filePath: path.resolve(file) };
 96→}
 97→
 98→/**
 99→ * Run the setup() export from a loaded setup module.
100→ *
101→ * Calls `module.setup(scope, parentContext?)` and returns the setup_context.
102→ * Supports both sync and async setup functions. Applies SHATTER_SETUP_TIMEOUT.
103→ */
104→export async function runSetup(
105→  setupModule: SetupModule,
106→  scope: string,
107→  _level: SetupLevel,
108→  parentContext?: SetupContextStack | null,
109→): Promise<unknown> {
110→  const setupFn = setupModule.exports["setup"];
111→  if (typeof setupFn !== "function") {
112→    throw new Error(
113→      `Setup file "${setupModule.filePath}" does not export a setup() function. ` +
114→      `Available exports: ${Object.keys(setupModule.exports).join(", ")}`,
115→    );
116→  }
117→
118→  const result = (setupFn as (scope: string, parentContext?: SetupContextStack | null) => unknown)(
119→    scope,
120→    parentContext ?? null,
121→  );
122→
123→  // Handle async setup functions
124→  if (result != null && typeof (result as PromiseLike<unknown>).then === "function") {
125→    const timeoutMs = getSetupTimeoutMs();
126→    return Promise.race([
127→      result as Promise<unknown>,
128→      new Promise<never>((_, reject) =>
129→        setTimeout(() => reject(new Error(`Setup timed out after ${timeoutMs}ms`)), timeoutMs),
130→      ),
131→    ]);
132→  }
133→
134→  return result;
135→}
136→
137→/**
138→ * Run the teardown() export from a loaded setup module.
139→ *
140→ * Calls `module.teardown(scope, setupContext)`. Supports async teardown.
141→ */
142→export async function runTeardown(
143→  setupModule: SetupModule,
144→  scope: string,
145→  setupContext: unknown,
146→): Promise<void> {
147→  const teardownFn = setupModule.exports["teardown"];
148→  if (typeof teardownFn !== "function") {
149→    throw new Error(
150→      `Setup file "${setupModule.filePath}" does not export a teardown() function. ` +
151→      `Available exports: ${Object.keys(setupModule.exports).join(", ")}`,
152→    );
153→  }
154→  const result = (teardownFn as (scope: string, ctx: unknown) => unknown)(scope, setupContext);
155→
156→  // Handle async teardown functions
157→  if (result != null && typeof (result as PromiseLike<unknown>).then === "function") {
158→    const timeoutMs = getSetupTimeoutMs();
159→    await Promise.race([
160→      result as Promise<unknown>,
161→      new Promise<never>((_, reject) =>
162→        setTimeout(() => reject(new Error(`Teardown timed out after ${timeoutMs}ms`)), timeoutMs),
163→      ),
164→    ]);
165→  }
166→}
167→
168→/**
169→ * Load a generator module file. The file should export named functions
170→ * that produce values when called.
171→ */
172→export function loadGeneratorModule(file: string): GeneratorModule {
173→  const exports = loadAndTranspile(file);
174→  return { exports, filePath: path.resolve(file) };
175→}
